INSERT INTO developer (id_developer, name, description) VALUES
(1, 'CD Projekt RED', 'Polish studio founded in 2002, known for The Witcher series and Cyberpunk 2077. Pioneers of open-world narrative RPGs.'),
(2, 'FromSoftware', 'Japanese studio founded in 1986, creators of Dark Souls, Elden Ring and Sekiro. Famous for challenging action RPGs.'),
(3, 'Larian Studios', 'Belgian studio founded in 1996, known for Divinity: Original Sin series and Baldurs Gate 3. Specialists in deep turn-based RPGs.'),
(4, 'Mojang Studios', 'Swedish studio founded in 2009, creators of Minecraft. One of the best-selling games of all time with over 300 million copies sold.'),
(5, 'Supergiant Games', 'American indie studio founded in 2009, known for Bastion, Transistor, Pyre and Hades. Praised for art and storytelling.'),
(6, 'Team Cherry', 'Australian indie duo founded in 2014, creators of Hollow Knight. Known for intricate hand-drawn metroidvania design.'),
(7, 'Bethesda Game Studios', 'American studio founded in 2001, creators of The Elder Scrolls and Fallout series. Known for vast open-world RPGs.'),
(8, 'Rockstar Games', 'American studio founded in 1998, known for Grand Theft Auto and Red Dead Redemption series. Leaders in open-world storytelling.'),
(9, 'Naughty Dog', 'American studio founded in 1984, creators of The Last of Us and Uncharted. Known for cinematic single-player experiences.'),
(10, 'Santa Monica Studio', 'American studio founded in 1999, creators of God of War series. Pioneers of epic action games with mythological settings.'),
(11, 'Coffee Stain Studios', 'Swedish studio founded in 2010, known for Satisfactory and Goat Simulator. Specialists in creative simulation games.'),
(12, 'Mega Crit', 'American indie studio founded in 2017, creators of Slay the Spire. Defined the modern roguelike deckbuilder genre.'),
(13, 'Concerned Ape', 'Solo developer Eric Barone, creator of Stardew Valley. One of the most successful indie games ever made by a single person.'),
(14, 'Arrowhead Game Studios', 'Swedish studio founded in 2009, creators of Helldivers series. Known for co-op action games with satirical sci-fi themes.'),
(15, 'Sony Interactive Entertainment', 'Japanese-American studio network founded in 1993. Publishers of many PlayStation exclusives including Astro Bot and Spider-Man.'),
(16, 'Insomniac Games', 'American studio founded in 1994, creators of Spider-Man and Ratchet & Clank. Known for polished action-adventure titles.'),
(17, 'Slavic Magic', 'Solo developer Greg Styczeń, creator of Manor Lords. Inspired by medieval German city-building and historical warfare.'),
(18, 'Game Science', 'Chinese studio founded in 2014, creators of Black Myth: Wukong. First major Chinese AAA action RPG studio.'),
(19, 'Ninja Theory', 'British studio founded in 2000, creators of Hellblade: Senuas Sacrifice. Known for narrative-driven games with mental health themes.'),
(20, 'Klei Entertainment', 'Canadian studio founded in 2005, known for Dont Starve, Oxygen Not Included and Mark of the Ninja. Masters of survival simulations.');
