INSERT INTO operating_system (id_operating_system, name, description) VALUES
(1, 'Windows', 'Windows je nejuniverzálnější herní platforma s podporou pro obrovské množství her, od retro titulů až po nejnovější AAA trháky. Díky zpětné kompatibilitě a technologiím jako DirectX, většina her na trhu běží právě na Windows 10 a 11.'),
(2, 'MacOS', 'Na macOS je podporována celá řada her, od nativních titulů pro Apple Silicon (čipy M1/M2/M3) až po populární hry. Mezi špičkové hry patří Baldur’s Gate 3, Resident Evil: Village, Lies of P, řada Tomb Raider, Civilization VI, The Sims 4 či Minecraft.'),
(3, 'GNU/Linux', 'Na Linuxu je dnes podporováno obrovské množství her, a to jak nativně (přímo pro Linux), tak přes vrstvy kompatibility (Proton/Wine). Díky našé platformě je herní knihovna na Linuxu velmi široká.');
